import React, { useState, useRef, useCallback, useEffect } from 'react';

const theme = {
  colors: {
    primary: '#8b5cf6',
    background: '#0a0a0a',
    surface: '#111111',
    surfaceAlt: '#1a1a1a',
    border: '#2a2a2a',
    text: '#fafafa',
    textSecondary: '#a1a1aa',
    textMuted: '#52525b',
    blue: '#38bdf8',
    yellow: '#fbbf24',
    pink: '#f472b6',
    green: '#a3e635',
    orange: '#fb923c',
    red: '#f43f5e',
  },
  font: "'JetBrains Mono', monospace",
};

const NUM_ARMS = 5;
const Q_VALUES = [1.2, 2.3, 0.8, 1.9, 1.5];
const TRUE_VALUES = [1.0, 1.8, 0.5, 2.8, 1.3];
const ARM_LABELS = ['A', 'B', 'C', 'D', 'E'];
const GREEDY_IDX = 1;
const TRUE_BEST_IDX = 3;

export default function App() {
  const [epsilon, setEpsilon] = useState(0.1);
  const [counts, setCounts] = useState([0, 0, 0, 0, 0]);
  const [totalReward, setTotalReward] = useState(0);
  const [totalTrials, setTotalTrials] = useState(0);
  const [lastAction, setLastAction] = useState(null);
  const [lastExplored, setLastExplored] = useState(null);
  const [lastRand, setLastRand] = useState(null);
  const [showTrue, setShowTrue] = useState(false);
  const [playing, setPlaying] = useState(false);
  const [flash, setFlash] = useState(null);

  const epsRef = useRef(epsilon);
  const playingRef = useRef(false);
  const intervalRef = useRef(null);
  const tickRef = useRef(0);

  useEffect(() => { epsRef.current = epsilon; }, [epsilon]);

  const selectionProbs = Q_VALUES.map((_, i) => {
    if (i === GREEDY_IDX) return (1 - epsilon) + epsilon / NUM_ARMS;
    return epsilon / NUM_ARMS;
  });

  const sampleOne = useCallback(() => {
    const eps = epsRef.current;
    const rand = Math.random();
    let action, explored;
    if (rand < eps) {
      action = Math.floor(Math.random() * NUM_ARMS);
      explored = true;
    } else {
      action = GREEDY_IDX;
      explored = false;
    }
    const reward = TRUE_VALUES[action] + (Math.random() - 0.5) * 0.4;
    setCounts(p => { const n = [...p]; n[action]++; return n; });
    setTotalReward(p => p + reward);
    setTotalTrials(p => p + 1);
    setLastAction(action);
    setLastExplored(explored);
    setLastRand(rand);
    setFlash(action);
    setTimeout(() => setFlash(null), 300);
  }, []);

  const runBatch = useCallback((n) => {
    const eps = epsRef.current;
    let lastA = null, lastE = null, lastR = 0;
    let rewardSum = 0;
    const deltas = [0, 0, 0, 0, 0];
    for (let i = 0; i < n; i++) {
      const rand = Math.random();
      let action;
      if (rand < eps) {
        action = Math.floor(Math.random() * NUM_ARMS);
        lastE = true;
      } else {
        action = GREEDY_IDX;
        lastE = false;
      }
      const reward = TRUE_VALUES[action] + (Math.random() - 0.5) * 0.4;
      deltas[action]++;
      rewardSum += reward;
      lastA = action;
      lastR = rand;
    }
    setCounts(p => p.map((c, i) => c + deltas[i]));
    setTotalReward(p => p + rewardSum);
    setTotalTrials(p => p + n);
    setLastAction(lastA);
    setLastExplored(lastE);
    setLastRand(lastR);
  }, []);

  const startPlay = () => {
    if (playingRef.current) return;
    playingRef.current = true;
    setPlaying(true);
    tickRef.current = 0;
    intervalRef.current = setInterval(() => {
      if (tickRef.current >= 20 || !playingRef.current) {
        clearInterval(intervalRef.current);
        playingRef.current = false;
        setPlaying(false);
        return;
      }
      runBatch(10);
      tickRef.current++;
    }, 120);
  };

  const stopPlay = useCallback(() => {
    playingRef.current = false;
    setPlaying(false);
    if (intervalRef.current) clearInterval(intervalRef.current);
  }, []);

  const reset = () => {
    stopPlay();
    setCounts([0, 0, 0, 0, 0]);
    setTotalReward(0);
    setTotalTrials(0);
    setLastAction(null);
    setLastExplored(null);
    setLastRand(null);
    setFlash(null);
  };

  useEffect(() => { return () => { if (intervalRef.current) clearInterval(intervalRef.current); }; }, []);

  const maxCount = Math.max(...counts, 1);
  const avgReward = totalTrials > 0 ? (totalReward / totalTrials) : 0;
  const optimalReward = TRUE_VALUES[TRUE_BEST_IDX];

  const exploitWidth = Math.round((1 - epsilon) * 100);
  const exploreWidth = 100 - exploitWidth;

  return (
    <div style={{ background: theme.colors.background, minHeight: '100vh', fontFamily: theme.font, color: theme.colors.text, display: 'flex', justifyContent: 'center', padding: '16px 12px' }}>
      <div style={{ maxWidth: 580, width: '100%' }}>
        {/* Title */}
        <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: 12 }}>
          <div style={{ fontSize: 17, fontWeight: 700, letterSpacing: '-0.3px' }}>Epsilon-Greedy Bandit</div>
          <div style={{ display: 'flex', gap: 6 }}>
            <button onClick={sampleOne} disabled={playing} style={{ background: theme.colors.primary, color: '#fff', border: 'none', borderRadius: 6, padding: '5px 10px', fontSize: 11, fontFamily: theme.font, cursor: 'pointer', opacity: playing ? 0.5 : 1 }}>Sample 1</button>
            <button onClick={playing ? stopPlay : startPlay} style={{ background: playing ? theme.colors.red : theme.colors.surfaceAlt, color: theme.colors.text, border: '1px solid ' + theme.colors.border, borderRadius: 6, padding: '5px 10px', fontSize: 11, fontFamily: theme.font, cursor: 'pointer' }}>{playing ? 'Stop' : 'Run 200'}</button>
            <button onClick={reset} style={{ background: theme.colors.surfaceAlt, color: theme.colors.textSecondary, border: '1px solid ' + theme.colors.border, borderRadius: 6, padding: '5px 10px', fontSize: 11, fontFamily: theme.font, cursor: 'pointer' }}>Reset</button>
          </div>
        </div>

        {/* Epsilon Slider */}
        <div style={{ background: theme.colors.surface, borderRadius: 10, padding: '12px 16px', marginBottom: 10 }}>
          <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: 8 }}>
            <span style={{ fontSize: 12, color: theme.colors.textSecondary }}>epsilon</span>
            <span style={{ fontSize: 18, fontWeight: 700, color: epsilon === 0 ? theme.colors.green : epsilon >= 1 ? theme.colors.orange : theme.colors.primary }}>{epsilon.toFixed(2)}</span>
          </div>
          <input type="range" min="0" max="1" step="0.01" value={epsilon} onChange={e => setEpsilon(parseFloat(e.target.value))} style={{ width: '100%', accentColor: theme.colors.primary, height: 6 }} />
          {/* Explore/Exploit bar */}
          <div style={{ display: 'flex', marginTop: 8, borderRadius: 4, overflow: 'hidden', height: 22, fontSize: 10, fontWeight: 600 }}>
            {exploitWidth > 0 && <div style={{ width: exploitWidth + '%', background: 'rgba(163,230,53,0.2)', color: theme.colors.green, display: 'flex', alignItems: 'center', justifyContent: 'center', transition: 'width 0.2s ease', minWidth: exploitWidth > 8 ? 0 : 0 }}>{exploitWidth > 15 ? 'EXPLOIT ' + exploitWidth + '%' : exploitWidth > 5 ? exploitWidth + '%' : ''}</div>}
            {exploreWidth > 0 && <div style={{ width: exploreWidth + '%', background: 'rgba(251,146,60,0.2)', color: theme.colors.orange, display: 'flex', alignItems: 'center', justifyContent: 'center', transition: 'width 0.2s ease' }}>{exploreWidth > 15 ? 'EXPLORE ' + exploreWidth + '%' : exploreWidth > 5 ? exploreWidth + '%' : ''}</div>}
          </div>
        </div>

        {/* Last action info */}
        <div style={{ height: 24, display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: 11, color: theme.colors.textSecondary, marginBottom: 6 }}>
          {lastAction !== null && lastRand !== null && (
            <span>
              rand = <span style={{ color: theme.colors.text, fontWeight: 600 }}>{lastRand.toFixed(3)}</span>
              {lastExplored
                ? <span> {'<'} {epsilon.toFixed(2)} <span style={{ color: theme.colors.orange, fontWeight: 600, marginLeft: 4 }}>EXPLORE</span> <span style={{ marginLeft: 4 }}>-></span> Arm {ARM_LABELS[lastAction]}</span>
                : <span> {'>='} {epsilon.toFixed(2)} <span style={{ color: theme.colors.green, fontWeight: 600, marginLeft: 4 }}>EXPLOIT</span> <span style={{ marginLeft: 4 }}>-></span> Arm {ARM_LABELS[lastAction]} (best Q)</span>
              }
            </span>
          )}
          {lastAction === null && <span style={{ color: theme.colors.textMuted }}>Click "Sample 1" or "Run 200" to see selections</span>}
        </div>

        {/* Arms */}
        <div style={{ display: 'flex', gap: 6, marginBottom: 8 }}>
          {Q_VALUES.map((q, i) => {
            const isGreedy = i === GREEDY_IDX;
            const isTrueBest = i === TRUE_BEST_IDX;
            const isSelected = lastAction === i;
            const isFlashing = flash === i;
            const prob = selectionProbs[i];
            const countPct = totalTrials > 0 ? counts[i] / totalTrials : 0;
            return (
              <div key={i} style={{
                flex: 1, background: theme.colors.surface, borderRadius: 8, padding: '10px 6px',
                border: '2px solid ' + (isFlashing ? (lastExplored ? theme.colors.orange : theme.colors.green) : isGreedy ? 'rgba(163,230,53,0.3)' : theme.colors.border),
                transition: 'border-color 0.3s, background 0.3s',
                textAlign: 'center',
                position: 'relative',
              }}>
                {/* Arm label */}
                <div style={{ fontSize: 13, fontWeight: 700, marginBottom: 4, color: isSelected ? theme.colors.text : theme.colors.textSecondary }}>
                  {ARM_LABELS[i]}
                  {isGreedy && <span style={{ fontSize: 9, color: theme.colors.green, display: 'block', marginTop: 1 }}>greedy</span>}
                  {!isGreedy && <span style={{ fontSize: 9, color: 'transparent', display: 'block', marginTop: 1 }}>.</span>}
                </div>

                {/* Q-value */}
                <div style={{ fontSize: 11, color: theme.colors.textMuted, marginBottom: 2 }}>Q</div>
                <div style={{ fontSize: 16, fontWeight: 700, color: theme.colors.blue, marginBottom: 6 }}>{q.toFixed(1)}</div>

                {/* True value */}
                {showTrue && (
                  <div style={{ marginBottom: 6 }}>
                    <div style={{ fontSize: 10, color: theme.colors.textMuted }}>True</div>
                    <div style={{ fontSize: 14, fontWeight: 700, color: isTrueBest ? theme.colors.pink : theme.colors.textSecondary }}>{TRUE_VALUES[i].toFixed(1)}
                      {isTrueBest && <span style={{ fontSize: 9, color: theme.colors.pink }}> best!</span>}
                    </div>
                  </div>
                )}

                {/* Probability bar */}
                <div style={{ fontSize: 9, color: theme.colors.textMuted, marginBottom: 3 }}>P(select)</div>
                <div style={{ height: 48, background: theme.colors.surfaceAlt, borderRadius: 4, position: 'relative', overflow: 'hidden', marginBottom: 4 }}>
                  <div style={{
                    position: 'absolute', bottom: 0, left: 0, right: 0,
                    height: (prob * 100) + '%',
                    background: isGreedy ? 'rgba(163,230,53,0.25)' : 'rgba(251,146,60,0.2)',
                    borderRadius: 4,
                    transition: 'height 0.3s ease',
                  }} />
                  <div style={{ position: 'absolute', inset: 0, display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: 11, fontWeight: 600, color: theme.colors.text }}>
                    {(prob * 100).toFixed(0)}%
                  </div>
                </div>

                {/* Count */}
                {totalTrials > 0 && (
                  <div style={{ fontSize: 11, color: theme.colors.textSecondary, marginTop: 4 }}>
                    <span style={{ fontWeight: 600, color: theme.colors.text }}>{counts[i]}</span>
                    <span style={{ fontSize: 9, color: theme.colors.textMuted }}> / {totalTrials}</span>
                  </div>
                )}
              </div>
            );
          })}
        </div>

        {/* Controls row: show true + stats */}
        <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: 8 }}>
          <button onClick={() => setShowTrue(!showTrue)} style={{
            background: showTrue ? 'rgba(244,114,182,0.15)' : theme.colors.surfaceAlt,
            color: showTrue ? theme.colors.pink : theme.colors.textSecondary,
            border: '1px solid ' + (showTrue ? 'rgba(244,114,182,0.3)' : theme.colors.border),
            borderRadius: 6, padding: '5px 12px', fontSize: 11, fontFamily: theme.font, cursor: 'pointer',
          }}>
            {showTrue ? 'Hide' : 'Reveal'} True Values
          </button>
          {totalTrials > 0 && (
            <div style={{ display: 'flex', gap: 16, fontSize: 11 }}>
              <div>
                <span style={{ color: theme.colors.textMuted }}>Avg reward: </span>
                <span style={{ color: avgReward > 2.0 ? theme.colors.green : theme.colors.yellow, fontWeight: 700 }}>{avgReward.toFixed(2)}</span>
              </div>
              {showTrue && (
                <div>
                  <span style={{ color: theme.colors.textMuted }}>Optimal: </span>
                  <span style={{ color: theme.colors.pink, fontWeight: 700 }}>{optimalReward.toFixed(1)}</span>
                </div>
              )}
            </div>
          )}
        </div>

        {/* Insight */}
        <div style={{
          background: theme.colors.surface, borderRadius: 8, padding: '10px 14px',
          fontSize: 11, color: theme.colors.textSecondary, lineHeight: 1.5,
          borderLeft: '3px solid ' + (epsilon === 0 ? theme.colors.green : epsilon >= 1 ? theme.colors.orange : theme.colors.primary),
          transition: 'border-color 0.3s',
        }}>
          <span style={{ color: epsilon === 0 ? theme.colors.green : epsilon >= 1 ? theme.colors.orange : theme.colors.primary, fontWeight: 600 }}>
            {epsilon === 0 ? 'Pure Exploit: ' : epsilon >= 1 ? 'Pure Explore: ' : 'Balancing: '}
          </span>
          {epsilon === 0 && !showTrue && 'Always picks Arm B (highest Q=2.3). Seems optimal... but is it? Try "Reveal True Values" to see what you\'re missing.'}
          {epsilon === 0 && showTrue && 'Always picks Arm B (Q=2.3, true=1.8). But Arm D\'s true value is 2.8! Without exploration, you\'ll never discover it. Increase epsilon to explore.'}
          {epsilon > 0 && epsilon < 0.3 && !showTrue && 'Mostly exploits Arm B, but ' + (epsilon * 100).toFixed(0) + '% of the time explores randomly. Run trials to see the distribution!'}
          {epsilon > 0 && epsilon < 0.3 && showTrue && totalTrials === 0 && 'With epsilon=' + epsilon.toFixed(2) + ', you\'ll occasionally try Arm D and discover its true value (2.8) beats Arm B (1.8). Run 200 trials to see!'}
          {epsilon > 0 && epsilon < 0.3 && showTrue && totalTrials > 0 && 'Exploration found Arm D ' + counts[TRUE_BEST_IDX] + ' times! Avg reward: ' + avgReward.toFixed(2) + '. Compare: pure greedy would average ~1.8 (Arm B\'s true value).'}
          {epsilon >= 0.3 && epsilon < 1 && !showTrue && 'Heavy exploration (' + (epsilon * 100).toFixed(0) + '%). You\'ll try every arm often, but waste many picks on bad ones. Is this too much?'}
          {epsilon >= 0.3 && epsilon < 1 && showTrue && 'Exploring ' + (epsilon * 100).toFixed(0) + '% of the time. You\'ll find Arm D (true=2.8) often, but also waste picks on C (true=0.5). The sweet spot is a small epsilon.'}
          {epsilon >= 1 && 'Every action is random. Each arm picked ~20% of the time. You\'ll discover everything but never leverage what you learn!'}
        </div>
      </div>
    </div>
  );
}
